import { ethers } from "ethers";

const contractABI = [/* ABI of the smart contract */];
const contractAddress = "YOUR_CONTRACT_ADDRESS";

async function main() {
  if (typeof window.ethereum !== 'undefined') {
    const provider = new ethers.providers.Web3Provider(window.ethereum);
    await provider.send("eth_requestAccounts", []);
    const signer = provider.getSigner();
    const contract = new ethers.Contract(contractAddress, contractABI, signer);

    document.getElementById('sendTransaction').onclick = async () => {
      try {
        const functionName = document.getElementById('functionName').value;
        const paramsInput = document.getElementById('params').value;
        const params = JSON.parse(paramsInput);

        const transactionResponse = await contract[functionName](...params);
        await transactionResponse.wait();

        console.log('Transaction successful:', transactionResponse);
      } catch (error) {
        console.error('Error sending transaction:', error);
      }
    };
  } else {
    console.error('Ethereum window object not found');
  }
}

window.onload = main; 

